insert into public.experts (name, notification_email, years_experience, bio, long_bio, languages, modalities, client_concerns, therapist_note, certifications, specialties, is_active, is_bookable) values
  ('Dr. Gurmeet S. Narang', NULL, NULL, 'Dr. Gurmeet S. Narang aka Man of Happiness, is an author, public figure, and happiness leader, has published a book titled Thode ki zaroorat hai (All you need is less) which explores the secrets of happiness in human life.', 'Dr. Gurmeet S. Narang aka Man of Happiness, is an author, public figure, and happiness leader, has published a book titled Thode ki zaroorat hai (All you need is less) which explores the secrets of happiness in human life. He is the founder of India''s only eternal happiness organization, Tavleen Foundation, which works in the area of contemplative studies for the overall betterment of life by achieving peaceful and mind solutions. Dr. Narang has written a total of 9 books on happiness to reduce the suffering of all the living beings of the world.', array[]::text[], array['Happiness Coach'], array[]::text[], NULL, array['Happiness Coach'], array['specialized'], true, false),
  ('Aman Grewal', NULL, NULL, 'Aman Grewal is an entrepreneur, certified life and success coach, and master practitioner in Neuro-Linguistic Programming from the National Federation of NLP, USA. She has conducted workshops for numerous universities and colleges in India. Aman also won the crown of Mrs.', 'Aman Grewal is an entrepreneur, certified life and success coach, and master practitioner in Neuro-Linguistic Programming from the National Federation of NLP, USA. She has conducted workshops for numerous universities and colleges in India. Aman also won the crown of Mrs. India worldwide and was adjudicated in many fashion events and beauty pageants as a jury. She is, currently, the official mentor and pageant coach for several national-level pageants. She also owns a creative home decor brand Floraonwood.', array[]::text[], array['Neuro-Linguistic Programming'], array[]::text[], NULL, array['Life Coach'], array['specialized'], true, false),
  ('Dr. Abrar Multani', NULL, NULL, 'Dr. Abrar Multani is a bestselling author on health issues. He is a renowned physician in the nation who treats chronic and complicated cases with mastery through Ayurveda & Hijama.', 'Dr. Abrar Multani is a bestselling author on health issues. He is a renowned physician in the nation who treats chronic and complicated cases with mastery through Ayurveda & Hijama. He founded Incredible Ayurveda which is one of the most successfully run Ayurveda Clinics in India and is situated in the capital of Madhya Pradesh, Bhopal. He is also the President of an NGO named Smiling Hearts which is truly devoted to the needy but poor people for their health, nutrition, and education. Dr. Abrar Multani is best known for his best-selling books Beemar Hona Bhul Jaiyye (Forget to be ill), Mann Keliye Amrit ki Bunde (Prescription of Thoughts), 5 Pills For Depression and Stress, Beemariya Harengi, Jeena Sikha Dengi, Motape se Breakup, Kyun alag hai stripurush ka prem (Join Happy Couples Club). He is also a columnist in leading newspapers and magazines of nations like Dainik Bhaskar, NBT, Patrika, India Today, Aha! Zindagi etc. Dr. Abrar Multani is best known for his best-selling books Beemar Hona Bhul Jaiyye (Forget to be ill), Mann Keliye Amrit ki Bunde (Prescription of Thoughts), 5 Pills For Depression and Stress, Beemariya Harengi, Jeena Sikha Dengi, Motape se Breakup, Kyun alag hai stripurush ka prem (Join Happy Couples Club). He is also a columnist in leading newspapers and magazines of nation like Dainik Bhaskar, NBT, Patrika, India Today, Aha! Zindagi etc.', array[]::text[], array['Ayurveda and Hijama'], array[]::text[], NULL, array['Ayurveda and Hijama Practitioner'], array['family-relationship','specialized'], true, false),
  ('Riddhi Deora', NULL, NULL, 'Riddhi Deorah is an entrepreneur, parenting coach, and the founder of Easy Parenting Hub, a platform for parents to live a happy, holistic, and spiritual life. She studied Economics at the University of Cambridge and the London School of Economics.', 'Riddhi Deorah is an entrepreneur, parenting coach, and the founder of Easy Parenting Hub, a platform for parents to live a happy, holistic, and spiritual life. She studied Economics at the University of Cambridge and the London School of Economics. She also writes a weekly parenting column for Dainik Jagran and Har Zindagi, conducts workshops for corporates globally, and is a panel speaker for various International Summits.', array[]::text[], array['Parenting'], array[]::text[], NULL, array['Parenting Coach'], array['child-adolescent','specialized'], true, false),
  ('Coach Preeti Khare', NULL, NULL, 'Coach Preeti Khare is a motivational speaker, Professional Certified Coach recognized by the International Coach Federation (ICF-PCC), and founder of ENABLEance, which help couples to build and sustain their relationship. She has helped more than 5000 individuals by instructing and empowering them.', 'Coach Preeti Khare is a motivational speaker, Professional Certified Coach recognized by the International Coach Federation (ICF-PCC), and founder of ENABLEance, which help couples to build and sustain their relationship. She has helped more than 5000 individuals by instructing and empowering them. Coach Khare is the president of a UK-based independent regulator, The Nursing and Midwifery Council, Coaching Support Group, Bhopal, and MP WICCI Coaching Council. She is an MBA (HR), MSA from Central Michigan University, USA.', array[]::text[], array[]::text[], array[]::text[], NULL, array['Relationship and Leadership Coach'], array['family-relationship','specialized'], true, false),
  ('Jyoti Pande', NULL, NULL, 'Jyoti Pande is a happiness trainer, storyteller, and practicing psychologist with an experience of more than 20 years and holds multiple degrees and diplomas from various reputed universities across India in the field of psychology.', 'Jyoti Pande is a happiness trainer, storyteller, and practicing psychologist with an experience of more than 20 years and holds multiple degrees and diplomas from various reputed universities across India in the field of psychology. She is a certified happiness trainer from the Institute of Child Education and Psychology (ICEP), Europe. She is also a happiness &mindfulness coach from the Berkley Institute of Well-Being and Happitude and is trained in mindfulness at the Mindfulness School, UK. Being the partner of an Army Officer, she has been working effortlessly in the welfare activities for the families of Army Personnel and has conducted Mental Health awareness programs for more than 2000 families of Army Personnel. Having an anecdotist mind, Mrs. Pande unfolded as one of the founding members of the Indian Storytellers Healing Network (ISHN). She has a diverse network under her space SOUL KATHA where she develops need-based programs for various organizations, ranging from Storytelling to Mindfulness and the Science of happiness.', array[]::text[], array[]::text[], array[]::text[], NULL, array['Counseling Psychologist'], array['child-adolescent','family-relationship'], true, false),
  ('Rashmi Singh', 'rashmi@themindsolace.com', NULL, 'Rashmi is a Certified Life Coach, Wellbeing Coach, Mindfulness Mentor, and Founder of The Mind Solace. By using techniques such as NLP, SMART goal setting, mindset training, positive self-talk, and more, she empowers her clients to overcome obstacles, discover their potential, and live fulfilling lives.', 'Rashmi is a Certified Life Coach, Wellbeing Coach, Mindfulness Mentor, and Founder of The Mind Solace. By using techniques such as NLP, SMART goal setting, mindset training, positive self-talk, and more, she empowers her clients to overcome obstacles, discover their potential, and live fulfilling lives. She has conducted workshops to promote self-care and mindfulness for organizations, retreats, and wellness festivals. Rashmi''s approach is rooted in empathy, self-compassion, and positive transformation. Her mission is to help you thrive, find balance, and become the best version of yourself. She has created The Mind Solace which works as your personalized procrastination smasher and guides you to live a life full of happiness and discipline. With years of experience in the wellness field, she coaches people to understand their unique needs and helps them create a routine, ritual or practice that fits them best.', array[]::text[], array['Self-development'], array[]::text[], NULL, array['Life Coach'], array['specialized'], true, false),
  ('Gunjan Kamra', 'eqmindandyoga@gmail.com', '3+ Years of Experience', 'Introducing Gunjan Kamra, a top-ranked celebrity yoga instructor and the Founder & CEO of Equilibrium Mind and Yoga (@eqmindandyoga) based in Mumbai. She is an expert in Stress Management, Advanced Yoga Training and Therapeutic Healing.', 'Introducing Gunjan Kamra, a top-ranked celebrity yoga instructor and the Founder & CEO of Equilibrium Mind and Yoga (@eqmindandyoga) based in Mumbai. She is an expert in Stress Management, Advanced Yoga Training and Therapeutic Healing. </br> With over four years of experience, Gunjan and her team have trained 10,000+ individuals, 80+ influencers and celebrities, and 100+ corporate clients worldwide. Gunjan has worked with high-profile clients like Ekta Kapoor, Sanya Malhotra, Priya Mani, and Mrunal Thakur, and has partnered with organizations like Adobe, Abbott, Indigo, and Reliance. </br> Gunjan is a seasoned yoga practitioner for 15+ years, a long-distance runner and a trained Latin dancer. Gunjan also has a background as a business analyst for 8 years. In March 2020, she founded Equilibrium Mind and Yoga, offering holistic wellness solutions, including tailored yoga sessions, diet consultations, and lifestyle correction, to help individuals and corporates achieve sustainable health and happiness.', array[]::text[], array['Therapeutic healing through Yoga'], array[]::text[], NULL, array['Celebrity Yoga Trainer'], array['specialized'], true, false),
  ('Dr. Pritisha Saxena', 'ps@gmail.com', NULL, 'Dr. Pritisha Saxena: Psychiatrist with 5+ years'' experience. Director at Vijaya Clinics, associated with Enso Wellness. Expert in diagnosing mental he', 'Dr. Pritisha Saxena is a psychiatrist with more than 5 years of experience in the field of mental health wellness. She is the director and chief consultant at Vijaya Clinics based in Nagpur and is associated with Enso Wellness and Super You. Dr. Saxena has the expertise of diagnosing individuals having problems related to anxiety, depression, schizophrenia, ADHD, bipolar disorder, etc. She completed her MBBS from Jawaharlal Nehru Medical College, Sawangi, and registered with Maharashtra Medical Council in 2018. Beyond their clinical work, she actively engages in mental health advocacy and community outreach.', array[]::text[], array[]::text[], array[]::text[], NULL, array['Psychiatrist'], array['individual'], true, false),
  ('Dr Madhura Samudra', 'drms@gmail.com', '4+ Years of Experience', 'Dr. Madhura Samudra, a board-certified psychiatrist with 4+ years of experience, specializes in LGBTQIA-inclusive, sex-positive mental health. She ha', 'Dr Madhura Samudra is a compassionate and dedicated psychiatrist with over 4 years of experience in mental health and wellness. Having earned her medical degree from the Navi Mumbai, she completed her residency in psychiatry at Pune. She was involved in various educational and community outreach activities during her time as a resident. She was also awarded for her research activities for the best Papers in National conferences. She is board certified in psychiatry and is committed to providing comprehensive and personalized care to her patients. As a queer affirmative & sex positive mental health practitioner and an LGBTQIA ally, Dr Madhura is dedicated to creating a safe and inclusive space for individuals of all sexual orientations and gender identities. She understands the unique mental health needs of the LGBTQIA community and is committed to providing affirming and culturally competent care. In addition to her clinical practice, Dr Madhura is actively involved in research and education, with 20+ publications and research papers in indexed Medical Journals while contributing by speaking at national and international conferences. Her warm and empathetic nature, coupled with her expertise has earned her the trust and gratitude of her patients. She is dedicated to helping individuals achieve mental wellness, regain their equilibrium, and live fulfilling lives.', array['Hindi','English'], array['Evidence-based Medication','Management Conflict','Resolution Interpersonal Issues'], array[]::text[], NULL, array['Psychiatrist'], array['family-relationship'], true, false),
  ('Archana Singhal', 'info@mindwellcounsel.com', NULL, 'Archana Singhal is a dedicated Educator, Counsellor, and Family Therapist based in Delhi, India. As a member of the National Psychological Wellbeing Council and the Counsellors Council of India, she upholds the highest standards of care in her practice.', 'Archana Singhal is a dedicated Educator, Counsellor, and Family Therapist based in Delhi, India. As a member of the National Psychological Wellbeing Council and the Counsellors Council of India, she upholds the highest standards of care in her practice. She specializes in helping individuals navigate challenges such as stress, anxiety, PTSD, mild depression, low self-esteem, relationship issues, breakups, grief, career changes, and burnout. She also supports personal growth in areas like inner child healing, self-identity, emotional well-being, and self-acceptance. Her goal is to empower individuals to overcome their mental health challenges, build resilience, and lead fulfilling lives. Archana is passionate about guiding people toward self-discovery and lasting emotional well-being.', array[]::text[], array[]::text[], array[]::text[], NULL, array['Counseling Psychologist'], array['child-adolescent','family-relationship'], true, false),
  ('Dr. Ratna Mulay', 'ratnamulay@gmail.com', '28+', 'Dr. Ratna Mulay is a physician, human nutrition expert, and sports nutrition formulation specialist with over three decades of experience in clinica', 'Dr. Ratna Mulay is a physician, nutrition scientist, and expert in human nutrition and health product formulation, with over three decades of multidisciplinary experience spanning clinical medicine, pediatric and adolescent health, nutritional therapy, and public health research. With academic training in Medicine, Human Nutrition, Adolescent Pediatrics, and a PhD in Gender & Nutrition, she brings a rare integration of clinical insight and scientific nutrition expertise. Her work focuses on evidence-based nutritional science, micronutrient therapy, and the development of advanced nutritional formulations designed to support health, performance, and disease prevention across different life stages. Dr. Mulay has extensive experience designing and validating nutritional supplements for adults, women, adolescents, and athletes, ensuring formulations are clinically sound, safe, and biologically effective. Alongside her clinical and research work, she has contributed to national public health initiatives and epidemiological programs, including leadership roles in disease surveillance and health program management. Her research spans micronutrient deficiencies, maternal and adolescent nutrition, sarcopenia, and nutrition-driven recovery in disease conditions. As a nutrition and formulation expert, Dr. Mulay specializes in developing scientifically validated nutrition protocols and sports-oriented nutritional solutions that support metabolic health, performance optimization, muscle preservation, and recovery. Her approach integrates clinical medicine, nutritional biochemistry, and applied physiology to create practical, effective nutritional interventions. Known for her structured, research-driven approach, she combines scientific rigor with practical application to support individuals, health programs, and health product innovations aimed at improving long-term physical health and human performance.', array['English','Hindi'], array['Clinical Nutrition & Dietetics','Sports Nutrition Formulation','Nutritional Supplement R&D','Micronutrient Assessment & Therapy','Pediatric & Adolescent N'], array['“I want to improve my nutritional health and energy levels.” “I need a structured nutrition plan to support performance and recovery.” “I want to addr'], NULL, array['Nutritionist'], array['child-adolescent','specialized'], true, false),
  ('Rupal Sharma', 'head.expert@mindcafe.app', '3+ Years of Experience', 'Rupal Sharma is a counseling psychologist with 3+ years of experience, specializing in therapies like CBT, DBT, and Mindfulness. A silver medalist in Clinical Psychology, she focuses on anxiety, stress, depression, and self-image issues. Rupal creates a warm, empathetic, and confidential space, believing in her clients'' potential to overcome challenges.', 'Rupal Sharma is a counselling psychologist with an experience in individual counselling as well as group therapy. With 3+ years of experience in the field. She is committed to constantly work with my clients to help them develop a complete sense of wellbeing and a silver medalist in her Master’s in Clinical Psychology. Rupal’s areas of expertise include Cognitive-Behavioral therapy, Dialectical Behavioral therapy, Mindfulness based, Emotion focused and Solution focused therapy. Her therapeutic approach focuses on Humanistic and Positive approach to therapy. Building up a strong set of skills to address issues related to Anxiety, Stress, Depression, Mood related, Anger related Self-image and concept related, eating related, sleep related and several other mental health related challenges. Rupal’s Note: I walk with warmth, activeness, care and empathy. Soul believer in the potential of an individual to overcome anything they come across. Assuring to create a safe space and trustworthy environment while maintaining complete confidentiality of my clients.', array['Hindi','English'], array['Psychotherapy','Cognitive-Behavioral therapy','Dialectical Behavioral therapy','Mindfulness based','Emotion focused and Solution focused therapy'], array['I’m a short-tempered','I don’t feel like doing anything','I’m not able to work productively','I’m feeling underconfident'], 'As a Counselling Psychologist, I am dedicated to harness my strengths to foster a safe space and build meaningful connection with my clients while maintaining complete confidentiality. My approach is grounded in understanding the unique narratives of each individual and providing them adequate support in their journey towards healing and personal growth. Hence, "I welcome you to OPEN the door, TAKE a step ahead and DIVE in this journey of meeting your TRUE self!', array['Counseling Psychologist'], array['individual'], true, false),
  ('Rhea Pereira', 'Pereirarhea5@gmail.com', '5+ Years of Experience', 'Rhea Pereira: Counselling psychologist in Bhopal. Specializes in school counselling, developing behavioral plans, and delivering cognitive behavioral therapy. Offers virtual sessions for diverse mental health challenges.', 'Rhea Pereira is a counselling psychologist based in Bhopal with outstanding experience in providing counselling in schools wherein she conducts counselling sessions on demand for students and parents. She also develops and implements individualised behavioural plans to assist students in achieving academic and personal goals. Rhea has delivered cognitive behavioural therapy, including behaviour-tracking frameworks and cognitive restructuring to her clients. She also provides virtual online sessions to support people from diverse backgrounds in dealing with complex mental health difficulties.', array['Hindi','English'], array['Psychotherapy','Cognitive Behavioural Therapy'], array['Anxiety and stress management','Depression and mood disorders','Relationship issues (family and couples)','Grief and loss','Career and academic concerns'], 'As a counseling psychologist, my mission is to create a safe, supportive space where you can explore your thoughts, emotions, and challenges without judgment. I believe that every individual has the capacity for growth and healing, and my role is to guide and empower you through that journey. Whether you''re navigating stress, anxiety, relationship issues, or personal development, I''m here to help you discover new insights and tools to create a more fulfilling and balanced life. My approach is collaborative, compassionate, and tailored to your unique needs. Together, we can work toward your goals at your own pace, ensuring that you feel heard and understood every step of the way. I look forward to supporting you on this path of self-discovery and transformation.', array['Counseling Psychologist'], array['child-adolescent','family-relationship'], true, false),
  ('Gauri Ghate', 'gaurighate2000@gmail.com', '2+ Years of Experience', 'Gauri Ghate is a compassionate counseling psychologist with over 2 years of experience, known for her high emotional intelligence and ability to connect with clients from diverse backgrounds. She is dedicated to providing a safe, non-judgmental space for clients to explore their thoughts and emotions, using excellent listening skills to offer personalized support.', 'Gauri Ghate is compassionate and empathetic counselling psychologist with 2+ years of experience and possess high emotional intelligence that help her connect with people from diverse backgrounds and age groups. She has excellent listening skills to actively engage with clients, understand their concerns, and provide personalized support. She is committed to creating a safe, non-judgmental space for clients to explore their thoughts, emotions, and experiences.', array['English','Hindi','Marathi'], array['Psychotherapy','Cognitive-Behavioral therapy','Dialectical Behavioral therapy','Mindfulness based','Emotion focused and Solution focused therapy'], array['I am unable to manage academic stress','I want to be the happiest version of myself','I lack motivation to begin projects'], 'Patience is a virtue I hold dear, recognizing that every individual''s journey towards mental wellness is unique and may unfold at their own pace. My optimistic outlook on life empowers me to foster hope and resilience in those I work with, helping them navigate life''s challenges and cultivate a positive mindset. I am particularly drawn to Mindcafe''s holistic approach to mental and spiritual health and its commitment to providing accessible, high-quality services. I am eager to be part of a team that shares my passion for empowering individuals to achieve their full potential.', array['Counseling Psychologist'], array['individual'], true, false),
  ('Shreyal Jain', 'jainshreyal1197@gmail.com', '3+ Years of Experience', 'Shreyal Jain is a counselling psychologist with 3+ years of experience and a Master''s in Clinical Psychology from MSU Baroda. A certified Expressive Arts-Based Therapist, she specializes in working with children, adolescents, and older adults. Shreyal conducts mental health workshops and offers creative arts-based training, using therapy to help individuals discover their potential.', 'Shreyal Jain is a counselling psychologist with 3+ years of experience and is an Expressive Arts-Based Therapist and Psychologist with a Master''s in Clinical Psychology from MSU Baroda and holds a CID-UNESCO Certification. She specializes in working with children, adolescents, and older adults, using expressive arts therapy to foster emotional well-being and self-discovery. In addition to her therapeutic practice, Shreyal conducts life skills and mental health workshops for schools and offers creative arts-based workshops and training sessions to various groups and organizations. Shreyal is passionate about guiding people on their journey to mental wellness, using creativity and therapy to help them discover their true potential.', array['Hindi','English'], array['Psychotherapy','Child Therapy','Art-Based Therapy'], array['Overwhelming stress or anxiety affecting daily life','Persistent feelings of sadness or hopelessness','Difficulty managing emotions or controlling anger','Struggles with low self esteem or body image issues','Relationship conflicts and communication problems'], 'I understand that seeking therapy can feel like a big step, but I’m here to walk with you through it. My approach is warm and collaborative, focusing on creating a space where you feel heard and supported. Together, we’ll explore whatever challenges you’re facing-whether it’s stress, anxiety, or simply feeling stuck. I believe in using creative and practical techniques to help you understand yourself better, manage your emotions, and work through life’s ups and downs. My goal is to help you feel more empowered and at ease with where you are, while moving toward where you want to be.', array['Counseling Psychologist'], array['child-adolescent','family-relationship'], true, false),
  ('Charul Gupta', 'guptacharul473@gmail.com', '3+ Years of Experience', 'Charul Gupta is a counselling psychologist with over 2 years of experience, specializing in helping clients with stress, depression, anxiety, and lifestyle challenges. She offers a compassionate, non-judgmental space and is dedicated to empowering clients with practical tools and coping strategies to lead more balanced and fulfilling lives.', 'Charul Gupta is a counselling psychologist with 2+ Years of experience. Her main focus is always on the needs of my clients and work with people dealing with a variety of mental health issues, such as stress, depression, anxiety, and lifestyle challenges. Through her previous work experience, she has gained valuable insights that enhance my approach to therapy. Charul is committed to providing a safe, non-judgmental space where clients feel genuinely supported. My goal is to empower them by offering practical tools and coping strategies, guiding them towards a more balanced and fulfilling life.', array['Hindi','English'], array['sychotherapy','Cognitive Behavioural Therapy'], array['I am having Persistent negative emotions','I am not able to trust people easily','I panic even in situations which are harmless'], 'I am a counselling psychologist specialising in CBT, Interpersonal therapy, psychodynamic approach, relationship issues, anxiety and depression. I am committed to fostering a safe and trustworthy space where clients can feel secure, always ensuring their confidentiality is respected. I approach every interaction with warmth, enthusiasm, and genuine care, holding a strong belief in each individual''s capacity to conquer their challenges and to make them believe in themselves.', array['Counseling Psychologist'], array['family-relationship'], true, false),
  ('Radhika Gupta', 'radhikagupta213@gmail.com', '2+ Years of Experience', 'Radhika Gupta is a queer-affirmative, trauma-informed psychotherapist who creates a compassionate, non-judgmental space for healing. She tailors therapy to individual needs, focusing on identity, trauma, and relationships. Whether exploring queer identity or processing trauma, Radhika supports clients with care and authenticity.', 'Radhika Gupta is a queer-affirmative, trauma- and attachment-informed psychotherapist. Her work is rooted in person-centered values, creating a compassionate, non-judgmental space where clients feel truly seen and heard. She integrate various therapeutic approaches tailored to individual needs, focusing on identity, trauma, relationships, and mental health. Whether you''re exploring your queer journey, processing trauma, or seeking deeper self-understanding, She will support with care and authenticity. In our sessions, you’re the expert of your experience, and I’m here to guide you on your path to healing.', array['English','Hindi'], array['Psychotherapy','Cognitive-Behavioural therapy','Trauma-Informed therapy','Mindfulness based','Emotion focused and Solution focused therapy'], array['I am unable to manage academic stress','I want to be the happiest version of myself','I lack motivation to begin projects'], 'I am a queer affirmative, attachment and trauma-informed therapist who integrates various therapeutic approaches to meet the unique needs of each client. With a deep understanding of the complexities of identity, relationships, and trauma, I try to create a safe, inclusive space for healing. My eclectic approach combines evidence-based methods like cognitive-behavioural therapy, mindfulness, and psychodynamic techniques, ensuring a personalized and holistic experience for every individual I work with.', array['Clinical Psychologist'], array['family-relationship'], true, false),
  ('Ankita Ganguly', 'ankitaganguly113333@gmail.com', NULL, 'Ankita Ganguly is a Counselling Psychologist with clinical experience from King George''s Medical University’s Department of Psychiatry. She specializes in Cognitive-Behavioral, Mindfulness-Based, Emotion-Focused, and Solution-Focused therapies, using a humanistic approach to address anxiety, stress, depression, and other challenges.', 'Ankita Ganguly is a Counselling Psychologist with hands-on experience in psychological assessments and client intakes from her internship at King George''s Medical University’s Department of Psychiatry, Ankita has developed a strong foundation in clinical practice. She specializes in Cognitive-Behavioral Therapy (CBT), Mindfulness-Based Therapy, Emotion-Focused Therapy, and Solution-Focused Therapy, with a humanistic and positive approach to therapy. Her work focuses on addressing Anxiety, Stress, Depression, Mood Disorders, Anger Issues, Self-Image and Self-Concept, Eating Disorders, Sleep Disorders, Personality Disorders, Trauma Disorders, and Neurodevelopmental Disorders.', array['English','Bengali','Hindi'], array['Anxiety','Anger management','Relationship Problems','Stress Management'], array['I procrastinate a lot because I doubt my abilities','I feel worthless when I make mistakes','I need a natural way to handle anxiety and mood swings','I get lost in overthinking and worry','I feel like I don’t know who I really am'], 'I work hand in hand alongside my clients with empathy, warmth, and authenticity, believing deeply in the resilience of the human mind. My approach is not just about overcoming challenges but about empowering individuals to take ownership of their well-being. I strive to create a space where self-discovery, balance, and inner strength can flourish, helping each person build a life that feels fulfilling and true to them.', array['Counseling Psychologist'], array['family-relationship'], true, false);